import React from "react";
import ReactDom from "react-dom/client";
import "./styles.css";

function App() {
  return (
    <div className="card">
      <Avatar />
      <div className="data">
        <Intro />
        <SkillList />
      </div>
    </div>
  );
}

function Avatar() {
  return (
    <div>
      <img
        src="./my-photo.jpg"
        alt="a guy looking at the camera"
        className="avatar"
      />
    </div>
  );
}

function Intro() {
  return (
    <div>
      <h1>Mehdi Sadeghi</h1>
      <p>
        Junior Front-end developer and English teacher at Pardisan English
        institute. When not coding or teaching, I like to watch football or hit
        the gym, or just enjoy hanging out with my friends.
      </p>
    </div>
  );
}

function SkillList() {
  return (
    <div className="skill-list">
      <Skill name="JS" color="blue" />
      <Skill name="REACT" color="red" />
      <Skill name="HTML & CSS" color="green" />
      <Skill name="GIT" color="yellow" />
      <Skill name="GITHUB" color="orange" />
      <Skill name="ADVANCE ENGLISH" color="purple" />
    </div>
  );
}

function Skill(props) {
  return (
    <div className="skill" style={{ backgroundColor: props.color }}>
      <span>{props.name}</span>
    </div>
  );
}

const rootElement = document.getElementById("root");
const root = ReactDom.createRoot(rootElement);

root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>,
);
